#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <math.h>

#include "../common/exit_codes.h"

#define MAX_SIZE	20
#define MIN_SIZE	3
#define IRINA_PI 3.14159265358979323846

int main(void){
char lineN[32];
if (fgets(lineN, sizeof(lineN), stdin) == NULL || lineN[0] == '\n' || lineN[0] == '\r'){
fprintf(stderr, "������� ������ ���� ������ ������ N");
return no_input;
}

// ������ �� ������ �� 1� ������, ������� strtol �� ������ ������������
char * endptr;
long int N = strtol(lineN, &endptr, 10);
if (*endptr != '\n' && *endptr != '\0'){
fprintf(stderr, "N ������ ���� ����� ������. ��������: %s", lineN);
return data;
}

if (N < MIN_SIZE || N > MAX_SIZE){
fprintf(stderr, "N ������ ���� � ��������� [3;20]. ��������: %s", lineN);
return usage;
}

// �������. � � � ��� �������� � ������ �� �����
double x[MAX_SIZE], y[MAX_SIZE];
for (int i = 0; i < N; ++i){
x[i] = cos(i * 2 * IRINA_PI / N);
y[i] = sin(i * 2 * IRINA_PI / N);
}

for (int i = 0; i < N; ++i){
for (int j = 0; j < N; ++j){
if (i == j) printf("%8.3f ", 0.0);
else printf("%8.3f ", sqrt(pow(x[i] - x[j], 2) + pow(y[i] - y[j], 2)));
}
puts("\n");
}

return 0;
